import React, { useEffect, useMemo, useState } from 'react';
import Calendar from 'react-calendar';
import 'react-calendar/dist/Calendar.css';

import { useAuth } from '../../context/AuthContext';
import { bookingApi } from '../../api/bookingApi';

import BookingTabs from './BookingTabs';
import BookingStatusBadge from './BookingStatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ErrorAlert from '../../components/common/ErrorAlert';

const isSameDay = (a, b) =>
	a.getFullYear() === b.getFullYear() &&
	a.getMonth() === b.getMonth() &&
	a.getDate() === b.getDate();

const formatTime = (dateString) =>
	new Date(dateString).toLocaleTimeString(undefined, {
		hour: '2-digit',
		minute: '2-digit',
	});

const BookingCalendar = () => {
	const { isAdmin } = useAuth();
	const adminView = isAdmin?.() === true;

	const [selectedDate, setSelectedDate] = useState(new Date());
	const [bookings, setBookings] = useState([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState(null);

	useEffect(() => {
		const load = async () => {
			try {
				setLoading(true);
				setError(null);

				const data = adminView
					? await bookingApi.getAllBookings({})
					: await bookingApi.getUserBookings(1);

				setBookings(Array.isArray(data) ? data : []);
			} catch (err) {
				setError('Failed to load bookings');
			} finally {
				setLoading(false);
			}
		};

		load();
	}, [adminView]);

	const bookingsForDay = useMemo(() => {
		return bookings
			.filter((booking) => {
				if (!booking?.startTime) return false;
				const start = new Date(booking.startTime);
				return isSameDay(start, selectedDate);
			})
			.sort((a, b) => new Date(a.startTime) - new Date(b.startTime));
	}, [bookings, selectedDate]);

	const dateTitle = selectedDate.toLocaleDateString(undefined, {
		month: 'numeric',
		day: 'numeric',
		year: 'numeric',
	});

	if (loading) return <LoadingSpinner />;

	return (
		<div className="booking-page booking-calendar-page">
			<div className="booking-page-header">
				<div>
					<h1>Booking Calendar</h1>
					<p>View bookings by date.</p>
				</div>
			</div>

			<BookingTabs />

			{error ? <ErrorAlert message={error} /> : null}

			<section className="booking-calendar-grid">
				<div className="booking-calendar-widget">
					<Calendar
						onChange={(value) => setSelectedDate(value)}
						value={selectedDate}
					/>
				</div>

				<div className="booking-calendar-list">
					<h2>Bookings on {dateTitle}</h2>

					{bookingsForDay.length === 0 ? (
						<p className="no-data">No bookings for this date.</p>
					) : (
						<div className="booking-calendar-cards">
							{bookingsForDay.map((booking) => (
								<article key={booking.id} className="booking-calendar-card">
									<div className="booking-calendar-card-main">
										<h3>{booking.resourceName || 'Room'}</h3>
										<p className="booking-calendar-time">
											{formatTime(booking.startTime)} – {formatTime(booking.endTime)}
										</p>
										<p className="booking-calendar-purpose">
											{booking.purpose || 'No purpose provided'}
										</p>
									</div>
									<div className="booking-calendar-card-status">
										<BookingStatusBadge status={booking.status} />
									</div>
								</article>
							))}
						</div>
					)}
				</div>
			</section>
		</div>
	);
};

export default BookingCalendar;
